using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with a default resolver (handles any type automatically)
var webOptions = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1. GetTypeInfo<T>() — returns JsonTypeInfo<T> directly, no cast needed
JsonTypeInfo<Person> personInfo = webOptions.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"  Serialized: {json}");

Person? roundTripped = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"  Round-tripped: {roundTripped}");

// 2. TryGetTypeInfo<T>() — probe without throwing
//    With the default resolver every type resolves, so Person succeeds:
if (webOptions.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? probed))
    Console.WriteLine($"\nTryGetTypeInfo<Person> => resolved ({probed!.Type.Name})");
else
    Console.WriteLine("\nTryGetTypeInfo<Person> => not available");

// Now use a source-gen context that only knows about Person.
// Asking for Order will fail gracefully via TryGetTypeInfo<T>.
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = AppJsonContext.Default
};

if (restrictedOptions.TryGetTypeInfo<Order>(out JsonTypeInfo<Order>? orderInfo))
    Console.WriteLine($"TryGetTypeInfo<Order> => resolved ({orderInfo!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Order> => not available (resolver doesn't know this type)");

// Models
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

// Source-gen context that only registers Person
[JsonSerializable(typeof(Person))]
public partial class AppJsonContext : JsonSerializerContext;

